#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[101];
        scanf("%s", S);
        int len = strlen(S);
        int cnt[26] = {0};
        for (int i = 0; i < len; ++i) cnt[S[i] - 'A']++;
        int L = cnt['L' - 'A'];
        int Tt = cnt['T' - 'A'];
        int I = cnt['I' - 'A'];
        int M = cnt['M' - 'A'];
        int E = cnt['E' - 'A'];
        int ok = 0;
        if (len >= 10) {
            ok = (L >= 2 && Tt >= 2 && I >= 2 && M >= 2 && E >= 2);
        } else if (len == 9) {
            ok = (L >= 2 && Tt >= 2 && I >= 2 && M >= 2 && E >= 1);
        } else {
            ok = 0;
        }
        printf("%s\n", ok ? "YES" : "NO");
    }
    return 0;
}

